import {
  isThemeToken,
  pxProperties,
  sizingProperties,
} from '@lmb-it/kitsconcerto-types';

const SEMANTIC_TOKEN_NAMES = new Set([
  'primary', 'secondary', 'success', 'danger', 'warning', 'info',
  'text', 'text-secondary', 'bg', 'bg-subtle', 'border',
  'surface-ground', 'surface-card', 'surface-overlay', 'surface-hover',
]);

/**
 * Resolves a theme token string to a CSS `var()` reference.
 *
 * - `'blue.500'`       → `'var(--kits-blue-500)'`
 * - `'primary'`        → `'var(--kits-primary)'`
 * - `'$spacing.4'`     → `'var(--kits-space-4)'`
 * - `'$radii.lg'`      → `'var(--kits-radii-lg)'`
 * - `'$shadows.md'`    → `'var(--kits-shadow-md)'`
 * - `'$fontSizes.lg'`  → `'var(--kits-fontSize-lg)'`
 * - `'$fonts.body'`    → `'var(--kits-font-body)'`
 */
const resolveThemeTokenForWeb = (value: string): string => {
  // Dot-notation colour: blue.500 → var(--kits-blue-500)
  const dotMatch = value.match(/^([a-zA-Z]+)\.(\d+)$/);
  if (dotMatch) {
    return `var(--kits-${dotMatch[1]}-${dotMatch[2]})`;
  }

  // Prefixed tokens: $spacing.4 → var(--kits-space-4)
  if (value.startsWith('$')) {
    const dotIdx = value.indexOf('.');
    if (dotIdx > 1) {
      const category = value.substring(1, dotIdx);
      const key = value.substring(dotIdx + 1);
      switch (category) {
        case 'spacing':  return `var(--kits-space-${key})`;
        case 'radii':    return `var(--kits-radii-${key})`;
        case 'shadows':  return `var(--kits-shadow-${key})`;
        case 'fontSizes': return `var(--kits-fontSize-${key})`;
        case 'fonts':    return `var(--kits-font-${key})`;
      }
    }
  }

  // Semantic tokens: 'primary' → var(--kits-primary)
  if (SEMANTIC_TOKEN_NAMES.has(value)) {
    return `var(--kits-${value})`;
  }

  return value;
};

/** Converts a raw prop value to a CSS-compliant string. */
export const toCssValue = (
    key: string,
    value: string | number,
): string | number => {
  // Theme token resolution
  if (typeof value === 'string' && isThemeToken(value)) {
    const resolved = resolveThemeTokenForWeb(value);
    if (resolved !== value) return resolved;
  }

  // Opacity: 80 → 0.8
  if (key === 'opacity' && typeof value === 'number') {
    return value / 100;
  }

  // Sizing keywords: 'full' → '100%', 'screen' → '100vh'/'100vw'
  if (Object.values(sizingProperties).includes(key)) {
    if (value === 'full') return '100%';
    if (value === 'screen') {
      const isH = key.toLowerCase().includes('h');
      const isNotW = !key.toLowerCase().includes('w');
      return isH && isNotW ? '100vh' : '100vw';
    }
  }

  // Bare numbers → px for applicable properties
  if (typeof value === 'number' && Object.values(pxProperties).includes(key)) {
    return `${value}px`;
  }

  return value;
};
